#!/usr/bin/env python3# -*- coding: utf-8 -*-"""ClawTeam 鍗忚皟浜鸿嚜鍔ㄥ喅绛栧紩鎿?鏍规嵁閿欒绫诲瀷鍜岄噸璇曟鏁拌嚜鍔ㄥ喅瀹氾細retry / skip / abort"""import jsonimport sys# 鍐崇瓥瑙勫垯琛?DECISION_RULES = {    "powershell_regex": {        "patterns": ["鏃犳硶璇嗗埆", "姝ｅ垯琛ㄨ揪寮?, "璇硶閿欒", "$鍙橀噺", "闈炴硶瀛楃"],        "action": "retry",        "reason": "PowerShell regex 閿欒锛屽彲杞箟鍚庨噸璇?,        "new_timeout": 60    },    "subprocess_timeout": {        "patterns": ["瓒呮椂", "timeout", "timed out"],        "action": "retry",        "reason": "瀛愯繘绋嬭秴鏃讹紝澧炲姞瓒呮椂鏃堕棿閲嶈瘯",        "new_timeout": 120    },    "file_not_found": {        "patterns": ["鎵句笉鍒?, "not found", "涓嶅瓨鍦?, "璺緞閿欒"],        "action": "skip",        "reason": "鏂囦欢涓嶅瓨鍦紝璺宠繃璇ヤ换鍔?    },    "syntax_error": {        "patterns": ["璇硶閿欒", "syntax error", "IndentationError", "SyntaxError"],        "action": "abort",        "reason": "浠ｇ爜璇硶閿欒锛岄渶浜哄伐淇浠ｇ爜"    },    "permission_denied": {        "patterns": ["鏉冮檺", "permission", "鎷掔粷璁块棶"],        "action": "abort",        "reason": "鏉冮檺涓嶈冻锛岄渶浜哄伐浠嬪叆"    },    "unknown": {        "patterns": [],        "action": "skip",        "reason": "鏈煡閿欒锛岄粯璁よ烦杩?    }}def classify_error(error_message):    """鏍规嵁閿欒淇℃伅鍖归厤閿欒绫诲瀷锛堜笉鍖哄垎澶у皬鍐欙級"""    msg_lower = error_message.lower()    for err_type, rule in DECISION_RULES.items():        for pattern in rule["patterns"]:            if pattern.lower() in msg_lower:                return err_type    return "unknown"def decide(error_type, error_message, retry_count=0):    """鍋氬嚭鍐崇瓥"""    if retry_count >= 3:        return {"action": "abort", "reason": "閲嶈瘯娆℃暟瓒呰繃3娆★紝缁堟", "error_type": error_type}    # auto 妯″紡锛氳嚜鍔ㄦ帹鏂敊璇被鍨?    if error_type == "auto":        inferred = classify_error(error_message)        return {            "action": DECISION_RULES[inferred]["action"],            "reason": DECISION_RULES[inferred]["reason"],            "new_timeout": DECISION_RULES[inferred].get("new_timeout"),            "error_type": inferred        }    rule = DECISION_RULES.get(error_type, DECISION_RULES["unknown"])    return {        "action": rule["action"],        "reason": rule["reason"],        "new_timeout": rule.get("new_timeout"),        "error_type": error_type    }def main():    if len(sys.argv) < 3 or sys.argv[1] != "decide":        print("鐢ㄦ硶: python auto-decider.py decide <error_type> \"<error_message>\" [retry_count]")        print("鍙敤 error_type:", list(DECISION_RULES.keys()) + ["auto"])        sys.exit(1)    error_type = sys.argv[2]    error_message = sys.argv[3] if len(sys.argv) > 3 else ""    retry_count = int(sys.argv[4]) if len(sys.argv) > 4 else 0    # 鑷姩鍒嗙被锛堝鏋滀紶鍏ョ殑鏄?unknown 鎴栨湭璇嗗埆锛岀敤 classify 鎺ㄦ柇鐪熷疄绫诲瀷锛?    # auto mode: classify automatically and route to decide()    if error_type == "auto":        inferred = classify_error(error_message)        result = decide(inferred, error_message, retry_count)        print(json.dumps(result, ensure_ascii=False, indent=2))        return    # Auto-classify unknown/unrecognized types    if error_type == "unknown" or error_type not in DECISION_RULES:        inferred = classify_error(error_message)        if inferred != "unknown":            error_type = inferred    result = decide(error_type, error_message, retry_count)    print(json.dumps(result, ensure_ascii=False, indent=2))if __name__ == "__main__":    main()